import{_ as e,o as t,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"100. Incident Reporting Investigation And Prevention","description":"","frontmatter":{"title":"100. Incident Reporting Investigation And Prevention","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/ohs/100-incident-reporting-investigation-and-prevention.md","filePath":"ebas/allied-health/ohs/100-incident-reporting-investigation-and-prevention.md"}'),r={name:"ebas/allied-health/ohs/100-incident-reporting-investigation-and-prevention.md"};function a(s,n,p,d,l,g){return t(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="_100-incident-reporting-investigation-and-prevention" tabindex="-1">100. Incident Reporting Investigation And Prevention <a class="header-anchor" href="#_100-incident-reporting-investigation-and-prevention" aria-label="Permalink to &quot;100. Incident Reporting Investigation And Prevention&quot;">​</a></h1><p><strong>100.1</strong> The Employer will facilitate timely reporting of incidents by Employees and ensure Employees who report incidents are appropriately supported.</p><p><strong>100.2</strong> Following an incident, the Employer will as soon as practicable:</p><p><strong>(a)</strong> provide the Employee/s with post incident support services;</p><p><strong>(b)</strong> take appropriate action to prevent further injury to Employees;</p><p><strong>(c)</strong> conduct an incident investigation in a timely manner and implement workplace controls to prevent the incident recurring; and</p><p><strong>(d)</strong> provide information regarding the Employee’s rights as relevant including the making and lodging of a workers compensation claim and reporting to police.</p><p><strong>100.3</strong> The Employer shall provide information, instruction and training to Employees and management staff regarding the importance of timely reporting, procedures regarding incident reporting, and linking this to incident investigation and prevention.</p>',8)])])}const v=e(r,[["render",a]]);export{m as __pageData,v as default};
